import {MainScenariosEventMap, MicroScenariosEventMap} from "./event/acp";
import {UseApplicationParams} from "./type";
import {AppSystemCommProtocol} from "./ascp";

export interface MicroAcpScenariosListenerMap {
}

export interface MicroAcpMethodMap {
    useApplication: (params: UseApplicationParams) => void
    logout: () => void
}


export function startSubAcp(overriddenMicroApp : string, handlerMap = {} as MicroAcpScenariosListenerMap) {
    return new SubAcp(overriddenMicroApp, handlerMap)
}

class SubAcp extends AppSystemCommProtocol implements MicroAcpMethodMap {
    constructor(appName: string, acpScenarioHandlerMapFromProps: MicroAcpScenariosListenerMap) {
        const eventHandlerMap = new Map() as Map<symbol | string, Function>
        (Object.keys(acpScenarioHandlerMapFromProps) as (keyof typeof acpScenarioHandlerMapFromProps)[]).forEach((handlerName) => {
            eventHandlerMap.set(MicroScenariosEventMap[handlerName], acpScenarioHandlerMapFromProps[handlerName])
        })

        super(appName, eventHandlerMap);
    }

    useApplication(params: UseApplicationParams) {
        this.eventBus.emit(MainScenariosEventMap.onUseApplication, params)
    }

    logout() {
        this.eventBus.emit(MainScenariosEventMap.onLogout)
    }
}



